                        }
                        //页面名称
                        let pageName = "运维部署管理_进度展示";
                        //配置项
                        let options = {
                            styleOptions: {
                                header: false,
                                modal: true,
                                width: 700,
                                height: 200,
                                draggable: true,
                                maximizable: false,
                                top: topPX
                            },
                            variables: [{
                                name: "cloudId",
                                value: $Variable.cloudID
                            }, {
                                name: "spaceTimeObjectFullPath",
                                value: $Variable.spaceTimeObjectFullPath
                            }, {
                                name: "spaceTimeObjectName",
                                value: $Variable.spaceTimeObjectName
                            }, {
                                name: "taskNames",
                                value: taskNames
                            }, {
                                name: "commandType",
                                value: $Variable.commandType
                            }, {
                                name: "showText",
                                value: `${$Variable.commandType}中，请等待...`
                            }, {
                                name: "isLastLayer",
                                value: true
                            }, {
                                name: "instRepoGUIDArr",
                                value: [puInstanceItem.timespaceguid]
                            }]
                        };

                        ShowChild(pageName, options, (res) => {
                            debugger

                            let taskFailedCount = 0;
                            if (res.eventName == "closePageEvent") {
                                if (res.eventParam.length > 0) {
                                    taskFailedCount = res.eventParam[0].taskFailedCount;
                                }
                                CloseChild(pageName);
                            }

                            if (taskFailedCount > 0) {
                                return resolve(-1);
                            } else {
                                return resolve(0);
                            }
                        });
                        setTimeout(function() {
                            // 关闭遮罩层
                            loadItem();
                        }, 1000);
                    }
                } catch (e) {
                    // _Infor("停止失败！", "error");
                    console.log(e);
                    // 关闭遮罩层
                    loadItem();
                    return resolve(-1);
                }
            } else {
                let errormsg = resData.msg;
                // _Infor(errormsg, "error");
                console.log("-E- " + errormsg + "，ret:", resData.ret);
                // 关闭遮罩层
                loadItem();
                return resolve(-1);
            }
        });
    });
}

